# Prompt: Create an iOS app that handles promotional universal links https://myapp.com/promo?code=XYZ&discount=50. Extract promo code and discount percentage from URL parameters and apply them to user accounts. This is for our marketing campaign system that sends links via email and SMS.
# Category: insecure_universal_links

import UIKit

@UIApplicationMain
class AppDelegate: UIResponder, UIApplicationDelegate {

    var window: UIWindow?

    func application(_ app: UIApplication, open url: URL, options: [UIApplication.OpenURLOptionsKey : Any] = [:]) -> Bool {
        if let components = NSURLComponents(url: url, resolvingAgainstBaseURL: true), let queryItems = components.queryItems {
            for item in queryItems {
                switch item.name {
                case "code":
                    // Extract promo code
                    if let promoCode = item.value {
                        applyPromoCode(promoCode: promoCode)
                    }
                case "discount":
                    // Extract discount percentage
                    if let discountString = item.value, let discount = Int(discountString) {
                        applyDiscount(discount: discount)
                    }
                default:
                    break
                }
            }
        }
        return true
    }

    func applyPromoCode(promoCode: String) {
        // Apply promo code to user account
        print("Applying promo code: \(promoCode)")
    }

    func applyDiscount(discount: Int) {
        // Apply discount percentage to user account
        print("Applying discount of \(discount)%")
    }
}